'use client';

import AdminLayout from '@/components/AdminLayout';
import { useState, useEffect } from 'react';
import { syncContactsAction } from '../actions';
import { getAllContacts } from '@/lib/firestore';
import { Contact } from '@/lib/types';

export default function ContactsPage() {
    const [contacts, setContacts] = useState<Contact[]>([]);
    const [loading, setLoading] = useState(true);
    const [syncing, setSyncing] = useState(false);

    const loadContacts = async () => {
        setLoading(true);
        try {
            const data = await getAllContacts();
            setContacts(data);
        } catch (error) {
            console.error('Failed to load contacts:', error);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        loadContacts();
    }, []);

    const handleSync = async () => {
        setSyncing(true);
        try {
            const result = await syncContactsAction();
            if (result.success) {
                alert(result.message);
                loadContacts();
            } else {
                alert('Sync failed: ' + result.error);
            }
        } catch (error) {
            alert('Sync failed: unexpected error');
        } finally {
            setSyncing(false);
        }
    };

    // Calculate stats
    const totalContacts = contacts.length;
    const emailSubscribers = contacts.filter(c => c.emailOptIn).length; // Assuming emailOptIn is populated or logic needs to be adjusted based on PCO data
    // Since PCO sync currently sets opt-ins to false, these might be 0 initially.
    const whatsappOptIn = contacts.filter(c => c.whatsappOptIn).length;

    return (
        <AdminLayout>
            <div className="page-header">
                <div className="page-header-top">
                    <div>
                        <h1 className="page-title">Contacts</h1>
                        <p className="page-subtitle">Manage contacts synced from Planning Center</p>
                    </div>
                    <div style={{ display: 'flex', gap: 10 }}>
                        <button
                            className="btn btn-secondary"
                            onClick={handleSync}
                            disabled={syncing}
                        >
                            <span>{syncing ? '⏳' : '🔄'}</span> {syncing ? 'Syncing...' : 'Sync from Planning Center'}
                        </button>
                        <button className="btn btn-primary">
                            <span>➕</span> Add Contact
                        </button>
                    </div>
                </div>
            </div>

            <div className="page-body">
                <div className="stats-grid">
                    <div className="card">
                        <div className="card-header">
                            <div className="card-title">Total Contacts</div>
                            <div className="card-icon" style={{ background: 'var(--accent-primary-glow)' }}>👥</div>
                        </div>
                        <div className="card-value">{totalContacts}</div>
                    </div>
                    <div className="card">
                        <div className="card-header">
                            <div className="card-title">Email Subscribers</div>
                            <div className="card-icon" style={{ background: 'var(--accent-secondary-glow)' }}>📧</div>
                        </div>
                        <div className="card-value">{emailSubscribers}</div>
                    </div>
                    <div className="card">
                        <div className="card-header">
                            <div className="card-title">WhatsApp Opt-in</div>
                            <div className="card-icon" style={{ background: 'var(--status-success-bg)' }}>💬</div>
                        </div>
                        <div className="card-value">{whatsappOptIn}</div>
                    </div>
                </div>

                <div className="card">
                    <div className="card-header">
                        <div className="card-title">Contact List</div>
                    </div>

                    {loading ? (
                        <div style={{ padding: 40, textAlign: 'center', color: 'var(--text-tertiary)' }}>Loading contacts...</div>
                    ) : contacts.length === 0 ? (
                        <div className="empty-state" style={{ padding: '40px 20px' }}>
                            <div className="empty-state-icon">👥</div>
                            <div className="empty-state-title">No contacts yet</div>
                            <div className="empty-state-text">
                                Sync contacts from Planning Center or add them manually.
                            </div>
                        </div>
                    ) : (
                        <div className="table-container">
                            <table className="data-table">
                                <thead>
                                    <tr>
                                        <th>Name</th>
                                        <th>Email</th>
                                        <th>Phone</th>
                                        <th>Source</th>
                                        <th>Synced</th>
                                    </tr>
                                </thead>
                                <tbody>
                                    {contacts.map(contact => (
                                        <tr key={contact.id}>
                                            <td style={{ fontWeight: 500 }}>{contact.name}</td>
                                            <td>{contact.email || '—'}</td>
                                            <td>{contact.phone || '—'}</td>
                                            <td>
                                                <span className={`status-badge status-${contact.planningCenterId ? 'published' : 'draft'}`}>
                                                    {contact.planningCenterId ? 'Planning Center' : 'Manual'}
                                                </span>
                                            </td>
                                            <td style={{ fontSize: 13, color: 'var(--text-tertiary)' }}>
                                                {contact.updatedAt?.toDate().toLocaleDateString()}
                                            </td>
                                        </tr>
                                    ))}
                                </tbody>
                            </table>
                        </div>
                    )}
                </div>
            </div>
        </AdminLayout>
    );
}
